#include<bits/stdc++.h>using namespace std;int T;string s,t;int n,m;bool check(int x,int y){	int N=m-y+x;	for(int j=0;j<N;j++)	{		int i=y-j;		if(s[i]!=t[y-i+y-x])		{			return 0;		}		if(y-i+y-x==m-1)		{			return 1;		}	}	return true;}int main(){	cin>>T;	while(T--)	{		cin>>s>>t;		n=s.size();		m=t.size();		bool flag=0;		for(int i=0;i<n;i++)		{			if(s[i]!=t[0])			{				continue;			}			for(int j=i;j<n;j++)			{				if(s[j]!=t[j-i])				{					break;				}				if(check(i,j))				{					cout<<"YES\n";					flag=1;					break;				}			}			if(flag)			{				break;			}		}		if(!flag)		{			cout<<"NO\n";		}    } 	return 0;}